{"type": "email", "id": "email_001", "subject": "Bakery Sales Analysis Q1-Q3 2025", "from": "emma.williams@leesmarket.com", "from_name": "Emma Williams", "to": ["maria.gonzalez@leesmarket.com", "john.doe@leesmarket.com"], "cc": ["sarah.lee@leesmarket.com"], "date": "2025-10-01 09:00:00", "body": "Hello Maria and John,

